#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>
#define N 200001
#define INF 1000000000
typedef struct {
    int node;
    int weight;
} Pair;
typedef struct Node {
    Pair pair;
    struct Node *next;
} Node;
void add_edge(Node* adj[], int u, int v, int weight) {
    Node *new_node = (Node *)malloc(sizeof(Node));
    new_node->pair.node = v;
    new_node->pair.weight = weight;
    new_node->next = adj[u];
    adj[u] = new_node;
}
void bfs(int v, Node* adj[], bool vis[], int d[], int n) {
    int deque[N];
    int front = N / 2;
    int back = N / 2;
    deque[back++] = v;
    d[v] = 0;
    while (front < back) {
        int u = deque[front++];
        if (vis[u]) {
            continue;
        }
        vis[u] = true;
        Node *ptr = adj[u];
        while (ptr != NULL) {
            int node = ptr->pair.node;
            int weight = ptr->pair.weight;
            if (weight == 0) {
                deque[--front] = node;
                if (d[node] > d[u]) {
                    d[node] = d[u];
                }
            } else {
                deque[back++] = node;
                if (d[node] > d[u] + 1) {
                    d[node] = d[u] + 1;
                }
            }
            ptr = ptr->next;
        }
    }
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        Node* adj[N];
        bool vis[N];
        int d[N];
        for (int i = 1; i <= n; i++) {
            adj[i] = NULL;
            d[i] = INF;
            vis[i] = false;
        }
        for (int i = 0; i < m; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            add_edge(adj, x, y, 0);
            add_edge(adj, y, x, 1);
        }
        bfs(1, adj, vis, d, n);
        if (d[n] == INF) {
            printf("-1\n");
        } else {
            printf("%d\n", d[n]);
        }
    }
    return 0;
}

