#include <bits/stdc++.h>
using namespace std;
const int N = 2e5 + 1;
const int INF = 1e9;
vector<pair<int, int>> adj[N];
vector<bool> vis(N, 0);
int d[N];
void bfs(int v) {
    deque<int> q;
    q.push_back(v);
    d[v] = 0;
    while (!q.empty()) {
        int u = q.front();
        q.pop_front();
        if (vis[u]) {
            continue;
        }
        vis[u] = 1;
        for (auto x : adj[u]) {
            int node = x.first;
            int weight = x.second;
            if (weight == 0) {
                q.push_front(node);
                d[node] = min(d[node], d[u]);
            } else {
                q.push_back(node);
                d[node] = min(d[node], d[u] + 1);
            }
        }
    }
}
